class Solution:
    def maxValue(self, n: int, index: int, maxSum: int) -> int:
        left, right = 1, maxSum
        while left < right:
            mid = (left + right) // 2
            if self.check(mid, n, index, maxSum):
                left = mid + 1
            else:
                right = mid
        return left - 1
    def check(self, mid, n, index, maxSum):
        total = 0
        for i in range(n):
            if i <= index:
                total += mid
            else:
                total += mid - 1
        return total <= maxSum
